diff --git a/App/Layers/W1/BaseApp/CRM/Interaction/InteractionLogEntrySourceMgt.Codeunit.al b/App/Layers/W1/BaseApp/CRM/Interaction/InteractionLogEntrySourceMgt.Codeunit.al
new file mode 100644
index 00000000..bbfc3321
--- /dev/null
+++ b/App/Layers/W1/BaseApp/CRM/Interaction/InteractionLogEntrySourceMgt.Codeunit.al
@@ -0,0 +1,36 @@
+namespace Microsoft.CRM.Interaction;
+
+using Microsoft.CRM.Segment;
+
+codeunit 5075 "Interaction Log Entry Src. Mgt."
+{
+    SingleInstance = true;
+
+    var
+        CachedSegmentLine: Record "Segment Line" temporary;
+
+    procedure RegisterSegmentLine(EntryNo: Integer; SegmentLine: Record "Segment Line")
+    begin
+        ClearSegmentLine(EntryNo);
+
+        CachedSegmentLine := SegmentLine;
+        CachedSegmentLine."Segment No." := Format(EntryNo);
+        CachedSegmentLine."Line No." := EntryNo;
+        CachedSegmentLine.Insert();
+    end;
+
+    procedure GetSegmentLine(EntryNo: Integer; var SegmentLine: Record "Segment Line" temporary): Boolean
+    begin
+        if not CachedSegmentLine.Get(Format(EntryNo), EntryNo) then
+            exit(false);
+
+        SegmentLine := CachedSegmentLine;
+        exit(true);
+    end;
+
+    procedure ClearSegmentLine(EntryNo: Integer)
+    begin
+        if CachedSegmentLine.Get(Format(EntryNo), EntryNo) then
+            CachedSegmentLine.Delete();
+    end;
+}
